pub fn bind_d(a: &mut S2, b: R1) -> Result<R2, E0> {
    let mut item = b.item.clone();
    if item.parent != "-" {
        item.parent = "-".to_string();
        item.depth = 0;
        item.chain = vec![item.ident.clone()];
    }
    a.items.insert(item.ident.clone(), item.clone());
    Ok(R2 { item })
}
